where 1 = 1




  and (fm.name like #{criteria.blurry,jdbcType=VARCHAR}
     or fm.path like #{criteria.blurry,jdbcType=VARCHAR}
     or fm.component like #{criteria.blurry,jdbcType=VARCHAR})




  and fm.create_time >= #{criteria.startTime,jdbcType=TIMESTAMP}




  and fm.create_time <= #{criteria.endTime,jdbcType=TIMESTAMP}
